def sort_books_asc_desc_ending(n, m, titles):
    def custom_key(title):
        return tuple(
            (ord(title[i]) if i % 2 == 0 else -ord(title[i]))
            for i in range(m)
        )

    sorted_titles = sorted(enumerate(titles, start=1), key=lambda x: custom_key(x[1]))
    sorted_indices = [index for index, _ in sorted_titles]
    return sorted_indices

