def min_operations_to_portal(t, test_cases):
    results = []

    for case in range(t):
        n, m, grid = test_cases[case]

        min_operations = float('inf')

        # Iterate over all possible top-left corners of the sub-rectangle
        for i in range(n):
            for j in range(m):
                # Iterate over all possible dimensions of the sub-rectangle
                for a in range(5, n - i + 1):
                    for b in range(4, m - j + 1):
                        operations = 0

                        # Check the top and bottom borders
                        for x in range(b):
                            if x == 0 or x == b - 1:
                                # Corners can be any type, no operation needed
                                continue
                            # Top border
                            if grid[i][j + x] != '1':
                                operations += 1
                            # Bottom border
                            if grid[i + a - 1][j + x] != '1':
                                operations += 1

                        # Check the left and right borders
                        for y in range(1, a - 1):
                            # Left border
                            if grid[i + y][j] != '1':
                                operations += 1
                            # Right border
                            if grid[i + y][j + b - 1] != '1':
                                operations += 1

                        # Check the interior
                        for y in range(1, a - 1):
                            for x in range(1, b - 1):
                                if grid[i + y][j + x] != '0':
                                    operations += 1

                        # Update the minimum operations needed
                        min_operations = min(min_operations, operations)

        results.append(min_operations)

    return results

