def minimal_difference(t, test_cases):
    results = []
    for a, b, c in test_cases:
        total_duration = a * 1 + b * 2 + c * 3
        max_possible_sum = total_duration // 2

        dp = [False] * (max_possible_sum + 1)
        dp[0] = True

        # Process 1-minute songs
        for _ in range(a):
            for j in range(max_possible_sum, 0, -1):
                if j >= 1:
                    dp[j] = dp[j] or dp[j - 1]

        # Process 2-minute songs
        for _ in range(b):
            for j in range(max_possible_sum, 1, -1):
                if j >= 2:
                    dp[j] = dp[j] or dp[j - 2]

        # Process 3-minute songs
        for _ in range(c):
            for j in range(max_possible_sum, 2, -1):
                if j >= 3:
                    dp[j] = dp[j] or dp[j - 3]

        # Find the largest i such that dp[i] is True
        for i in range(max_possible_sum, -1, -1):
            if dp[i]:
                min_difference = total_duration - 2 * i
                results.append(min_difference)
                break

    return results

